const { Storage } = require('@google-cloud/storage');
const storage = new Storage();

/**
 * Responds to an HTTP request by serving a file from Google Cloud Storage.
 * The bucket and file path are provided as query parameters.
 *
 * @param {object} req The HTTP request object.
 * @param {object} res The HTTP response object.
 */
exports.serveFile = async (req, res) => {
  const bucketName = req.query.bucket;
  const filePath = req.query.filePath;

  if (!bucketName) {
    res.status(400).send('Bad Request: "bucket" query parameter is required.');
    return;
  }
  if (!filePath) {
    res.status(400).send('Bad Request: "filePath" query parameter is required.');
    return;
  }

  const file = storage.bucket(bucketName).file(filePath);

  try {
    // Check if the file exists and retrieve its metadata
    const [exists] = await file.exists();
    if (!exists) {
      res.status(404).send('File not found.');
      return;
    }

    const [metadata] = await file.getMetadata();

    // Set Content-Type header based on file metadata
    if (metadata.contentType) {
      res.setHeader('Content-Type', metadata.contentType);
    } else {
      // Fallback to a generic content type if not specified in metadata
      res.setHeader('Content-Type', 'application/octet-stream');
    }

    // Stream the file directly to the response
    file.createReadStream()
      .on('error', (err) => {
        console.error(`Stream error for ${bucketName}/${filePath}:`, err);
        res.status(500).send('Internal Server Error: Could not stream file.');
      })
      .pipe(res)
      .on('finish', () => {
        // The stream has finished, and res.end() is handled by pipe.
      });

  } catch (error) {
    console.error(`Error serving file ${bucketName}/${filePath}:`, error);

    // Handle specific GCS errors
    if (error.code === 404) {
      res.status(404).send('File or bucket not found.');
    } else if (error.code === 403) {
      res.status(403).send('Permission denied to access file or bucket.');
    } else {
      res.status(500).send('Internal Server Error: Failed to retrieve file.');
    }
  }
};